<?php
function render_modulo_simple(string $titulo, string $url, array $columnas, array $registros, string $htmlFormulario, string $buscar): void {
?>
<div class="d-flex justify-content-between align-items-center mb-3"><h1 class="h4 mb-0"><?= e($titulo) ?></h1></div>
<div class="card mb-3"><div class="card-header">Nuevo registro</div><div class="card-body"><form method="POST" action="<?= e(url($url)) ?>" class="row g-2"><?= csrf_campo() ?><?= $htmlFormulario ?><div class="col-12"><button class="btn btn-primary btn-sm">Guardar</button></div></form></div></div>
<div class="card"><div class="card-header d-flex justify-content-between align-items-center"><div class="d-flex gap-2 align-items-center"><label class="small">Mostrar</label><select class="form-select form-select-sm" style="width:90px"><option>10</option><option>25</option></select></div><form method="GET" class="d-flex gap-2"><input name="q" class="form-control form-control-sm" value="<?= e($buscar) ?>" placeholder="Buscar"><button class="btn btn-outline-secondary btn-sm">Buscar</button></form></div><div class="table-responsive"><table class="table table-sm table-hover mb-0 tabla-admin"><thead><tr><?php foreach($columnas as $col): ?><th><?= e(ucwords(str_replace('_', ' ', $col))) ?></th><?php endforeach; ?><th class="text-end">Acciones</th></tr></thead><tbody><?php foreach($registros as $fila): ?><tr><?php foreach($columnas as $col): ?><td><?= e((string)($fila[$col] ?? '')) ?></td><?php endforeach; ?><td class="text-end"><div class="dropdown"><button class="btn btn-light btn-sm dropdown-toggle" data-bs-toggle="dropdown">Acciones</button><ul class="dropdown-menu dropdown-menu-end"><li><a class="dropdown-item" href="#">Ver</a></li><li><a class="dropdown-item" href="#">Editar</a></li><li><a class="dropdown-item text-danger" href="#" onclick="return confirm('¿Eliminar registro?')">Eliminar</a></li></ul></div></td></tr><?php endforeach; ?></tbody></table></div></div>
<?php }
